import React, { useEffect, useState } from "react";
import { Table, Tooltip } from "antd";
import { Trash2, Plus, Search, Pencil, BookOpen } from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { deleteABlogCat, getCategories, resetState } from "../features/bcategory/bcategorySlice";
import CustomModal from "../components/CustomModal";

const Blogcatlist = () => {
  const [open, setOpen] = useState(false);
  const [blogCatId, setblogCatId] = useState("");
  const [searchText, setSearchText] = useState("");
  const showModal = (e) => { setOpen(true); setblogCatId(e); };
  const hideModal = () => setOpen(false);

  const dispatch = useDispatch();
  useEffect(() => { dispatch(resetState()); dispatch(getCategories()); }, [dispatch]);
  const bCatState = useSelector((state) => state.bCategory.bCategories);

  const columns = [
    {
      title: "Category",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-3">
          <div className="vibe-icon" style={{ background: "rgba(139,92,246,0.1)" }}>
            <BookOpen size={17} style={{ color: "#8b5cf6" }} />
          </div>
          <div>
            <div className="font-bold text-[15px]" style={{ color: "var(--c-text-1)" }}>{text}</div>
            <div className="text-[11px]" style={{ color: "var(--c-text-3)" }}>Blog Category</div>
          </div>
        </div>
      ),
      sorter: (a, b) => a.name?.localeCompare(b.name),
    },
    {
      title: "ID",
      dataIndex: "key",
      width: 110,
      render: (text) => (
        <code className="text-[11px] font-bold px-2.5 py-1 rounded-md" style={{ background: "rgba(139,92,246,0.1)", color: "#8b5cf6" }}>
          BLOG-{String(text).padStart(3, "0")}
        </code>
      ),
    },
    {
      title: "Actions",
      width: 90,
      render: (_, record) => (
        <div className="flex items-center gap-2">
          <Link to={`/admin/blog-category/${record._id}`}>
            <Tooltip title="Edit"><button className="vibe-btn-edit"><Pencil size={14} /></button></Tooltip>
          </Link>
          <Tooltip title="Delete">
            <button className="vibe-btn-delete" onClick={() => showModal(record._id)}><Trash2 size={14} /></button>
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 = bCatState
    ?.filter((c) => !searchText || c.title.toLowerCase().includes(searchText.toLowerCase()))
    .map((cat, i) => ({ key: i + 1, _id: cat._id, name: cat.title })) || [];

  const deleteBlogCategory = (e) => {
    dispatch(deleteABlogCat(e));
    setOpen(false);
    setTimeout(() => dispatch(getCategories()), 100);
  };

  return (
    <div className="vibe-page space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <div className="w-1 h-4 rounded-full" style={{ background: "#8b5cf6" }} />
            <span className="text-[11px] font-bold uppercase tracking-widest" style={{ color: "#8b5cf6" }}>Content</span>
          </div>
          <h1 className="text-[26px] font-bold" style={{ color: "var(--c-text-1)", margin: 0 }}>Blog Categories</h1>
          <p className="text-[14px] mt-1" style={{ color: "var(--c-text-3)" }}>Manage editorial classifications and content taxonomy.</p>
        </div>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="relative flex-1 sm:flex-none">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: "var(--c-text-3)" }} />
            <input type="text" placeholder="Search categories..." className="vibe-search sm:w-60" onChange={(e) => setSearchText(e.target.value)} />
          </div>
          <Link to="/admin/blog-category">
            <button className="vibe-btn-primary" style={{ background: "#8b5cf6", boxShadow: "0 8px 24px rgba(139,92,246,0.3)" }}>
              <Plus size={18} /> Add Category
            </button>
          </Link>
        </div>
      </div>

      <div className="vibe-card">
        <div className="flex items-center gap-3 px-6 py-4" style={{ borderBottom: "1px solid var(--c-border)" }}>
          <div className="vibe-icon" style={{ background: "rgba(139,92,246,0.1)" }}>
            <BookOpen size={18} style={{ color: "#8b5cf6" }} />
          </div>
          <span className="font-bold text-[15px]" style={{ color: "var(--c-text-1)" }}>Blog Taxonomy</span>
          <span className="ml-1 text-[13px]" style={{ color: "var(--c-text-3)" }}>{data1.length} categories</span>
        </div>
        <Table columns={columns} dataSource={data1} pagination={{ pageSize: 12, showSizeChanger: false }} className="vibe-table" rowKey="key" />
      </div>

      <CustomModal hideModal={hideModal} open={open} performAction={() => deleteBlogCategory(blogCatId)}
        title="Delete Blog Category" content="This will remove the category from the system. Are you sure?" />
    </div>
  );
};

export default Blogcatlist;
